export function shuffleArr(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export function buildSession(levelKey, count = 12) {
  const pool = WORD_DB[levelKey] || [];
  const words = shuffleArr([...pool]).slice(0, Math.min(count, pool.length));
  const allJapanese = pool.map(w => w.japanese);
  return words.map(w => {
    const wrongPool = shuffleArr(allJapanese.filter(j => j !== w.japanese));
    return {
      english: w.english,
      japanese: w.japanese,
      correct: w.japanese,
      wrongs: wrongPool.slice(0, 3),
      phonetic: w.phonetic,
      sentence: w.sentence,
      pos: w.pos,
      category: w.category,
      img: w.img,
      levelKey,
    };
  });
}

export function buildWeakSession(stats, count = 12) {
  const allWords = [];
  for (const levelKey of Object.keys(WORD_DB)) {
    const pool = WORD_DB[levelKey];
    const allJapanese = pool.map(w => w.japanese);
    for (const w of pool) {
      const stat = stats[w.english];
      if (stat && stat.wrongCount > 0) {
        const wrongPool = shuffleArr(allJapanese.filter(j => j !== w.japanese));
        allWords.push({
          english: w.english,
          japanese: w.japanese,
          correct: w.japanese,
          wrongs: wrongPool.slice(0, 3),
          phonetic: w.phonetic,
          sentence: w.sentence,
          pos: w.pos,
          category: w.category,
          img: w.img,
          levelKey,
          weakScore: stat.wrongCount,
        });
      }
    }
  }
  return shuffleArr(allWords.sort((a,b)=>b.weakScore-a.weakScore).slice(0,50)).slice(0,count);
}
